            std::cin >> v;
            std::cout << "clamped int: " << clamp(v, lo, hi) << "\n";
        } else {
            double v;
            std::cin >> v;
            std::cout << "clamped double: " << clamp(v, flo, fhi) << "\n";
        }
    }

