#include <iomanip>
#include <iostream>
#include <string>
#include <sstream>

std::string formatReceiptLine(std::string name, double price,
                               std::string symbol = "$", double discount = 0.0) {
    std::ostringstream oss;
    if (discount == 0.0) {
        oss << symbol << std::fixed << std::setprecision(2) << price << " \xe2\x80\x94 " << name;
    } else {
        double discounted = price * (1.0 - discount / 100.0);
        oss << symbol << std::fixed << std::setprecision(2) << discounted
            << " \xe2\x80\x94 " << name << " (" << std::setprecision(1) << discount << "% off)";
    }
    return oss.str();
}

int main() {
    int n;
    std::cin >> n;
    std::cin.ignore();

    for (int i = 0; i < n; ++i) {
        std::string line;
        std::getline(std::cin, line);
        std::istringstream ss(line);

        std::string name, symbol;
        double price, discount;

        ss >> name >> price;
        if (ss >> symbol) {
            if (ss >> discount) {
                std::cout << formatReceiptLine(name, price, symbol, discount) << "\n";
            } else {
                std::cout << formatReceiptLine(name, price, symbol) << "\n";
            }
        } else {
            std::cout << formatReceiptLine(name, price) << "\n";
        }
    }

    return 0;
}

