constexpr double PI = 3.14159265358979;

std::string describeArea(double radius, bool rounded = false) {
    double area = PI * radius * radius;
    std::ostringstream oss;
    if (rounded)
        oss << "Circle area: " << static_cast<int>(std::round(area));
    else
        oss << "Circle area: " << std::fixed << std::setprecision(2) << area;
