    double area = width * height;
    std::ostringstream oss;
    if (rounded)
        oss << "Rectangle area: " << static_cast<int>(std::round(area));
    else
        oss << "Rectangle area: " << std::fixed << std::setprecision(2) << area;
    return oss.str();
